#include <stdio.h>
#include <math.h>
int main() {
  int n, temp, digits = 0;
  double sum = 0;
  scanf("%d", &n);
  temp = n;
  while (temp != 0) {
    digits++;
    temp /= 10;
  }
  temp = n;
  while (temp != 0) {
    int rem = temp % 10;
    sum += pow(rem, digits);
    temp /= 10;
  }
  if ((int)sum == n)
    printf("Armstrong number");
  else
    printf("Not Armstrong");
  return 0;
}

