#include <stdio.h>
#define MAX 5
int stack[MAX];
int top = -1;
void push(int x) {
  if (top == MAX - 1) {
    printf("Stack overflow\n");
    return;
  }
  stack[++top] = x;
}
int pop() {
  if (top == -1) {
    printf("Stack underflow\n");
    return -1;
  }
  return stack[top--];
}
int main() {
  push(10);
  push(20);
  push(30);
  printf("Popped: %d\n", pop());
  printf("Popped: %d\n", pop());
  return 0;
}

#include <stdio.h>
#define MAX 5
int queue[MAX];
int front = 0, rear = -1;
void enqueue(int x) {
  if (rear == MAX - 1) {
    printf("Queue full\n");
    return;
  }
  queue[++rear] = x;
}
int dequeue() {
  if (front > rear) {
    printf("Queue empty\n");
    return -1;
  }
  return queue[front++];
}
int main() {
  enqueue(5);
  enqueue(10);
  enqueue(15);
  printf("Dequeued: %d\n", dequeue());
  printf("Dequeued: %d\n", dequeue());
  return 0;
}

