#include <stdio.h>
int binSearch(int a[], int low, int high, int key) {
  if (low > high) return -1;
  int mid = (low + high) / 2;
  if (a[mid] == key) return mid;
  else if (a[mid] > key) return binSearch(a, low, mid - 1, key);
  else return binSearch(a, mid + 1, high, key);
}
int main() {
  int n, i, key, idx;
  int a[50];
  scanf("%d", &n);
  for (i = 0; i < n; i++) scanf("%d", &a[i]);
  scanf("%d", &key);
  idx = binSearch(a, 0, n - 1, key);
  if (idx == -1) printf("Not found");
  else printf("Found at index %d", idx);
  return 0;
}

